import{_ as l,o as a,c as e,O as t}from"./chunks/framework.4afe7240.js";const m=JSON.parse('{"title":"常用命令","description":"","frontmatter":{},"headers":[],"relativePath":"git/install.md","filePath":"git/install.md","lastUpdated":null}'),s={name:"git/install.md"},i=t(`<h1 id="常用命令" tabindex="-1">常用命令 <a class="header-anchor" href="#常用命令" aria-label="Permalink to &quot;常用命令&quot;">​</a></h1><ul><li>git branch -v 查看本地分支</li></ul><hr><ul><li>git branch -r 查看远程分支</li></ul><hr><ul><li>git branch -a 查看本地和远程分支</li></ul><hr><ul><li>git branch --delete/-d/-D(强制删除) dev 删除本地分支 <ul><li>git branch -d/--delete 的时候如果本地分支没有被合并就会提示这个问题</li><li>git branch -D 是强制删除，所以直接执行 强制删除就好了。</li></ul></li></ul><hr><ul><li>git push origin --delete dev 删除远程分支</li></ul><hr><ul><li>git checkout dev 切换本地分支</li></ul><hr><ul><li>git checkout -b dev 创建本地并切</li></ul><hr><ul><li>git checkout origin/dev 切换远程分支</li></ul><hr><ul><li>git push --set-upstream origin dev 创建远程分支</li></ul><hr><ul><li>git checkout -b dev origin/dev 创建本地并切换远程</li></ul><hr><ul><li>git merge dev1 合并分支 目前在 dev dev1 是另一条分支用 git merge dev1 会将 dev1 的文件添加到 dev</li></ul><hr><ul><li>git mv oldName newName 修改一个目录或者文件的名字</li></ul><hr><ul><li>git rm 1.txt 命令把一个文件删除，并把它从 git 的仓库管理系统中移除。</li></ul><hr><ul><li>git stash 恢复到上次提交的内容，同时备份本地所做的修改 (用于切换分支报错)</li></ul><hr><ul><li>git reflog 查询丢失文件</li></ul><hr><ul><li>git reset --hard HEAD@{12} 恢复</li></ul><hr><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#C3E88D;">$ git config --global user.name &quot;楼下小黑&quot;</span></span>
<span class="line"><span style="color:#C3E88D;">$ git config --global user.email &quot;1164240637@qq.com&quot;</span></span></code></pre></div><h1 id="生成-添加-ssh-公钥" tabindex="-1">生成/添加 SSH 公钥 <a class="header-anchor" href="#生成-添加-ssh-公钥" aria-label="Permalink to &quot;生成/添加 SSH 公钥&quot;">​</a></h1><ul><li>ssh-keygen -t ed25519 -C &quot;<a href="mailto:1164240637@qq.com" target="_blank" rel="noreferrer">1164240637@qq.com</a>&quot;</li><li>~/.ssh/id_ed25519.pub 查看</li><li>ssh -T <a href="mailto:git@gitee.com" target="_blank" rel="noreferrer">git@gitee.com</a></li></ul><h1 id="window-切户-git-账号" tabindex="-1">window 切户 git 账号 <a class="header-anchor" href="#window-切户-git-账号" aria-label="Permalink to &quot;window 切户 git 账号&quot;">​</a></h1><ol><li>打开控制面板，选择用户账户-&gt;管理你的凭据</li><li>点击 Windows 凭据，选择相应的 git 凭据，删除或修改</li><li>git config --global user.name &quot;username&quot; git config --global user.email &quot;<a href="mailto:xxx@xxx.com" target="_blank" rel="noreferrer">xxx@xxx.com</a>&quot;</li></ol><h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="远程与本地代码不一致" tabindex="-1">远程与本地代码不一致 <a class="header-anchor" href="#远程与本地代码不一致" aria-label="Permalink to &quot;远程与本地代码不一致&quot;">​</a></h2><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">! </span><span style="color:#89DDFF;">[</span><span style="color:#A6ACCD;">rejected</span><span style="color:#89DDFF;">]</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">master -&gt; master (non-fast-forward)</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">error: failed to push some refs to &#39;https://~.git</span><span style="color:#89DDFF;">&quot;</span></span></code></pre></div><blockquote><p>解决:<code>git pull --rebase origin master</code></p></blockquote><h2 id="_2-远程的记录和现在不同" tabindex="-1">2 远程的记录和现在不同 <a class="header-anchor" href="#_2-远程的记录和现在不同" aria-label="Permalink to &quot;2 远程的记录和现在不同&quot;">​</a></h2><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">! </span><span style="color:#89DDFF;">[</span><span style="color:#A6ACCD;">rejected</span><span style="color:#89DDFF;">]</span><span style="color:#A6ACCD;">          dev -&gt; dev (fetch first)</span></span></code></pre></div><blockquote><p>解决:<code>git push -f origin dev</code></p></blockquote><h2 id="_3-不允许提交不关联的历史代码" tabindex="-1">3 不允许提交不关联的历史代码 <a class="header-anchor" href="#_3-不允许提交不关联的历史代码" aria-label="Permalink to &quot;3 不允许提交不关联的历史代码&quot;">​</a></h2><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#F07178;">fatal</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">refusing to merge unrelated histories</span></span></code></pre></div><blockquote><p>解决办法是：在 git pull 和 git push 命令中添加–allow-unrelated-histories 让 git 允许提交不关联的历史代码。 git pull origin master --allow-unrelated-histories git push origin master --allow-unrelated-histories</p></blockquote>`,48),o=[i];function n(r,c,p,u,h,d){return a(),e("div",null,o)}const b=l(s,[["render",n]]);export{m as __pageData,b as default};
